using System;
using Avalonia;
using Avalonia.Controls;
using Avalonia.Headless;
using Avalonia.Threading;
using Avalonia.VisualTree;
using VisualRelay.App.ViewModels;
using VisualRelay.App.Views;
using VisualRelay.App.Views.Controls;
using VisualRelay.App.Views.Controls.Buttons;
using VisualRelay.Core.Configuration;
using VisualRelay.Domain;

namespace VisualRelay.Tests.Debug;

[Collection("Headless")]
public class DebugButtonTests
{
    [AvaloniaFact]
    public async Task Debug_SettingsButton_Click()
    {
        var env = new DictionaryEnvironmentAccessor();
        using var repo = TestRepository.Create();
        SettingsTestHelpers.WriteCommitConfig(repo, commitProofArtifacts: true);
        repo.WriteTask("alpha", "# Alpha\n");

        var vm = new MainWindowViewModel { RootPath = repo.Root, EnvironmentAccessor = env };
        await vm.LoadInitialAsync();
        var window = new MainWindow { DataContext = vm, Width = 1440, Height = 900 };
        window.Show();
        Dispatcher.UIThread.RunJobs();

        var topBar = SettingsTestHelpers.GetTopBar(window);
        Console.WriteLine($"TopBar found: {topBar != null}");

        var btn = topBar.FindControl<Button>("SettingsButton");
        Console.WriteLine($"SettingsButton found: {btn != null}, type: {btn?.GetType().FullName}");

        if (btn != null)
        {
            Console.WriteLine($"IsVisible: {btn.IsVisible}, IsEnabled: {btn.IsEnabled}");
            Console.WriteLine($"Bounds: {btn.Bounds}");
            Console.WriteLine($"IsArrangeValid: {btn.IsArrangeValid}");
            Console.WriteLine($"IsMeasureValid: {btn.IsMeasureValid}");
        }

        // Try to click
        var c = new Point(btn!.Bounds.Width / 2, btn.Bounds.Height / 2);
        var pt = btn.TranslatePoint(c, window) ?? c;
        Console.WriteLine($"Click point: {pt}");
        window.MouseDown(pt, MouseButton.Left);
        window.MouseUp(pt, MouseButton.Left);
        Dispatcher.UIThread.RunJobs();

        Console.WriteLine($"OwnedWindows count: {window.OwnedWindows.Count}");
        foreach (var owned in window.OwnedWindows)
        {
            Console.WriteLine($"  Owned: {owned.GetType().FullName}");
        }

        Console.WriteLine($"IsSettingsOpen: {vm.IsSettingsOpen}");

        window.Close();
    }
}
ENDOFFILE
